I'm adding a new webhook handler for a payment provider. Here's the controller method:

```typescript
@Post('payments/webhook')
async handlePaymentWebhook(@Body() body: any) {
  const event = body;
  if (event.type === 'payment.completed') {
    const booking = await this.prisma.booking.findFirst({ where: { stripePaymentIntentId: event.paymentIntentId } });
    await this.prisma.booking.update({ where: { id: booking.id }, data: { status: 'CONFIRMED' } });
    await this.prisma.payment.create({ data: { bookingId: booking.id, amount: event.amount, status: 'COMPLETED' } });
  }
  return { received: true };
}
```

I updated the AI service to add a new customer-facing chat feature. The key change is in ai.service.ts:

```typescript
async customerChat(businessId: string, customerId: string, question: string) {
  const customer = await this.prisma.customer.findUnique({ where: { id: customerId, businessId } });
  const business = await this.prisma.business.findUnique({ where: { id: businessId } });
  const history = await this.prisma.message.findMany({ where: { conversationId: customer.lastConversationId } });

  const prompt = `You are a helpful assistant for ${business.name}. Customer ${customer.name} asks: ${question}. Previous messages: ${history.map(m => m.content).join('\n')}`;

  const response = await this.claudeClient.complete(prompt);
  const parsed = JSON.parse(response);

  this.dailyCalls.set(businessId, { count: (this.dailyCalls.get(businessId)?.count || 0) + 1, date: new Date().toISOString().split('T')[0] });

  return { answer: parsed.answer, suggestions: parsed.suggestions };
}
```
